args.sparql:
SELECT ?person ?personLabel (xsd:integer(SUBSTR(STR(?appointmentDate), 1, 4)) - xsd:integer(SUBSTR(STR(?birthDate), 1, 4)) AS ?age)
WHERE {
  ?person wdt:P39 wd:Q16644626;
          wdt:P569 ?birthDate;
          wdt:P571 ?appointmentDate.
  ?person rdfs:label ?personLabel.
  FILTER(LANG(?personLabel) = 'en').
}
ORDER BY ?age
LIMIT 3
